tasks.solution:
#include <iostream>
using namespace std;

class Book {
public:
    string title;

    Book(string t) {
        title = t;
    }

    void display() {
        cout << "Book: " << title << endl;
    }
};

int main() {
    Book b("C++ Primer");
    b.display();
    return 0;
}

