tasks.solution:
#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> v;
    v.push_back(1);
    v.push_back(2);
    v.push_back(3);

    for (int x : v) {
        cout << x << " ";
    }
    cout << endl;
    return 0;
}
